{
  "intro": "You’re the overnight tech on a busy studio lot. A live stream keeps freezing, phones are lighting up, and the control room wants answers now.",
  "metrics": [
    "Signal",
    "Time",
    "Trust"
  ],
  "steps": [
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "You trace one frozen clip from camera to control room, noting each stop. One bad relay keeps showing up, and the room gets quiet as the pattern clicks.",
          "id": "s1_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Signal"
            },
            {
              "effect": "neutral",
              "metric": "Time"
            },
            {
              "effect": "positive",
              "metric": "Trust"
            }
          ],
          "text": "Follow one clip stop by stop"
        },
        {
          "alignment": "partial",
          "consequence": "You restart the control room screens. A few feeds return for a minute, but the stutter crawls back and people start hovering over your shoulder.",
          "id": "s1_c2",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Signal"
            },
            {
              "effect": "negative",
              "metric": "Time"
            },
            {
              "effect": "neutral",
              "metric": "Trust"
            }
          ],
          "text": "Restart the control room gear"
        },
        {
          "alignment": "weak",
          "consequence": "You tell every camera team to lower quality at once. The picture gets uglier, complaints get louder, and the freezes still hit random moments.",
          "id": "s1_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Signal"
            },
            {
              "effect": "negative",
              "metric": "Trust"
            }
          ],
          "text": "Lower quality on every camera"
        }
      ],
      "situation": "One camera feed freezes again, then snaps back. You need a fast way to figure out where the trouble starts before the director loses patience."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "You compare what leaves the camera with what reaches the next room. The labels match until one handoff, where pieces arrive out of order and late.",
          "id": "s2_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Signal"
            },
            {
              "effect": "positive",
              "metric": "Trust"
            }
          ],
          "text": "Compare what enters and leaves each handoff"
        },
        {
          "alignment": "partial",
          "consequence": "You swap one cable that looks worn. That line improves, but two other feeds still stumble, and the producer asks why the problem keeps moving.",
          "id": "s2_c2",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Signal"
            },
            {
              "effect": "negative",
              "metric": "Time"
            }
          ],
          "text": "Replace the worst-looking cable first"
        },
        {
          "alignment": "weak",
          "consequence": "You blame the camera operator and ask for a full reboot there. The operator loses a shot, tempers flare, and the control room still sees dropouts.",
          "id": "s2_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Trust"
            },
            {
              "effect": "negative",
              "metric": "Time"
            }
          ],
          "text": "Reboot the camera causing complaints"
        }
      ],
      "situation": "A floor runner says the bad feed looked fine in the hallway monitor. That means the problem may appear only after the signal passes through another room."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "You send a tiny test burst out and back along the same route. One return takes far longer than the others, and suddenly the weak spot has a name.",
          "id": "s3_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Signal"
            },
            {
              "effect": "positive",
              "metric": "Time"
            },
            {
              "effect": "positive",
              "metric": "Trust"
            }
          ],
          "text": "Send a small test out and back"
        },
        {
          "alignment": "partial",
          "consequence": "You watch the meters longer, hoping a pattern appears. You do spot a delay, but precious minutes drain away while the director drums fingers on glass.",
          "id": "s3_c2",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Signal"
            },
            {
              "effect": "negative",
              "metric": "Time"
            }
          ],
          "text": "Keep watching the live meters"
        },
        {
          "alignment": "weak",
          "consequence": "You reroute every feed through a spare path immediately. The spare path chokes under the load, and now more screens hiccup at once.",
          "id": "s3_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Signal"
            },
            {
              "effect": "negative",
              "metric": "Trust"
            },
            {
              "effect": "negative",
              "metric": "Time"
            }
          ],
          "text": "Move all feeds to the spare path"
        }
      ],
      "situation": "A surprise rehearsal starts early, doubling traffic through the building. At the same time, a quick test return arrives much slower than the outgoing signal."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "You isolate the relay that mishandles labeled pieces meant for one room. Other feeds steady almost immediately, and the producer finally stops shouting your name.",
          "id": "s4_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Signal"
            },
            {
              "effect": "positive",
              "metric": "Trust"
            }
          ],
          "text": "Bypass the relay sending pieces wrong"
        },
        {
          "alignment": "partial",
          "consequence": "You split traffic between two routes by guesswork. Some screens smooth out, but one key camera still freezes during close-ups.",
          "id": "s4_c2",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Signal"
            },
            {
              "effect": "neutral",
              "metric": "Trust"
            },
            {
              "effect": "negative",
              "metric": "Time"
            }
          ],
          "text": "Divide traffic across two routes"
        },
        {
          "alignment": "weak",
          "consequence": "You boost every sender to push harder. Fans whine, the rooms heat up, and the jammed relay keeps dropping the same chunks.",
          "id": "s4_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Signal"
            },
            {
              "effect": "negative",
              "metric": "Time"
            }
          ],
          "text": "Crank up every sender"
        }
      ],
      "situation": "The station manager walks in with a sponsor beside her. One relay cabinet is blinking wildly, and the biggest screen freezes right as they look up."
    },
    {
      "choices": [
        {
          "alignment": "strong",
          "consequence": "You show the route map, the delayed return, and the bad relay’s mismatch. The sponsor sees the stream recover live, and the room breaks into relieved applause.",
          "id": "s5_c1",
          "metricEffects": [
            {
              "effect": "positive",
              "metric": "Signal"
            },
            {
              "effect": "positive",
              "metric": "Trust"
            },
            {
              "effect": "positive",
              "metric": "Time"
            }
          ],
          "text": "Present the route and swap the bad relay"
        },
        {
          "alignment": "partial",
          "consequence": "You keep the workaround running and promise a deeper fix later. The show survives, but everyone knows the setup is still fragile.",
          "id": "s5_c2",
          "metricEffects": [
            {
              "effect": "neutral",
              "metric": "Signal"
            },
            {
              "effect": "positive",
              "metric": "Time"
            },
            {
              "effect": "neutral",
              "metric": "Trust"
            }
          ],
          "text": "Keep the workaround through the show"
        },
        {
          "alignment": "weak",
          "consequence": "You insist the issue is basically gone and do nothing else. Minutes later, the freeze returns during the sponsor mention, and every face in the room sours.",
          "id": "s5_c3",
          "metricEffects": [
            {
              "effect": "negative",
              "metric": "Signal"
            },
            {
              "effect": "negative",
              "metric": "Trust"
            }
          ],
          "text": "Declare victory and leave it alone"
        }
      ],
      "situation": "The show opens in two minutes. You have one shot to either lock in the fix or gamble that the stream holds under the heaviest load of the night."
    }
  ]
}

